/**
 * Unit Tests: TTS Service
 * Testa o módulo de Text-to-Speech multi-provider
 * @see src/lib/tts/tts-service.ts
 */

import { TTSService, listVoices } from '@/lib/tts/tts-service';
import type { TTSOptions } from '@/lib/tts/tts-service';

// Mock all external dependencies
jest.mock('child_process', () => ({
  exec: jest.fn(),
}));
jest.mock('util', () => ({
  ...jest.requireActual('util'),
  promisify: jest.fn().mockReturnValue(jest.fn().mockResolvedValue({ stdout: '', stderr: '' })),
}));
jest.mock('fs/promises', () => ({
  writeFile: jest.fn().mockResolvedValue(undefined),
  mkdir: jest.fn().mockResolvedValue(undefined),
  readFile: jest.fn().mockResolvedValue(Buffer.from('fake-audio-data')),
}));

jest.mock('@/lib/logger', () => ({
  Logger: jest.fn().mockImplementation(() => ({
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  })),
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

jest.mock('@/lib/supabase/service', () => ({
  getServiceRoleClient: jest.fn().mockReturnValue({
    storage: {
      from: jest.fn().mockReturnValue({
        upload: jest.fn().mockResolvedValue({ error: null }),
        getPublicUrl: jest.fn().mockReturnValue({
          data: { publicUrl: 'https://storage.example.com/tts/test.mp3' },
        }),
      }),
    },
  }),
}));

jest.mock('@/lib/resilience/circuit-breaker', () => ({
  withCircuitBreaker: jest.fn().mockImplementation(
    (_name: string, fn: () => Promise<unknown>) => fn()
  ),
}));

jest.mock('@/lib/resilience/retry', () => ({
  retryTTS: jest.fn().mockImplementation(
    (fn: () => Promise<unknown>) => fn()
  ),
}));

jest.mock('@/lib/tts/edge-tts-service', () => ({
  EdgeTTSService: {
    resolveVoice: jest.fn().mockReturnValue('pt-BR-FranciscaNeural'),
  },
}));

jest.mock('@/lib/config/timeout-config', () => ({
  withTimeout: jest.fn().mockImplementation(
    (promise: Promise<unknown>) => promise
  ),
  PIPELINE_TIMEOUTS: {
    ttsPerSlide: 60000,
  },
}));

jest.mock('@/lib/queue/concurrency-limiter', () => ({
  withTTSConcurrency: jest.fn().mockImplementation(
    (fn: () => Promise<unknown>) => fn()
  ),
}));

jest.mock('@/lib/middleware/idempotency-middleware', () => ({
  withIdempotency: jest.fn().mockImplementation(
    (_key: string, fn: () => Promise<unknown>) => fn()
  ),
  generateTTSIdempotencyKey: jest.fn().mockReturnValue('test-idempotency-key'),
}));

describe('TTS Service', () => {
  const originalEnv = { ...process.env };

  beforeEach(() => {
    jest.clearAllMocks();
    // Default: edge-tts provider (free fallback)
    process.env.TTS_PROVIDER = 'edge-tts';
    process.env.TTS_DEFAULT_VOICE = 'pt-BR-FranciscaNeural';
    process.env.TEMP_PATH = '/tmp';
    // Remove paid provider keys so edge-tts is used
    delete process.env.ELEVENLABS_API_KEY;
    delete process.env.AZURE_TTS_KEY;
    delete process.env.AZURE_SPEECH_KEY;
    delete process.env.GOOGLE_TTS_CREDENTIALS;
    delete process.env.GOOGLE_TTS_API_KEY;
  });

  afterEach(() => {
    process.env = { ...originalEnv };
  });

  describe('TTSService object', () => {
    it('should export synthesize and listVoices methods', () => {
      expect(TTSService).toBeDefined();
      expect(typeof TTSService.synthesize).toBe('function');
      expect(typeof TTSService.listVoices).toBe('function');
    });
  });

  describe('listVoices', () => {
    it('should return available voices', async () => {
      const voices = await listVoices();

      expect(Array.isArray(voices)).toBe(true);
      expect(voices.length).toBeGreaterThan(0);

      // Each voice should have id, name, and language
      voices.forEach((voice) => {
        expect(voice).toHaveProperty('id');
        expect(voice).toHaveProperty('name');
        expect(voice).toHaveProperty('language');
        expect(typeof voice.id).toBe('string');
        expect(typeof voice.name).toBe('string');
        expect(typeof voice.language).toBe('string');
      });
    });

    it('should include Portuguese voices', async () => {
      const voices = await listVoices();
      const ptVoices = voices.filter((v) => v.language === 'pt-BR');

      expect(ptVoices.length).toBeGreaterThan(0);
    });

    it('should include English voices', async () => {
      const voices = await listVoices();
      const enVoices = voices.filter((v) => v.language === 'en-US');

      expect(enVoices.length).toBeGreaterThan(0);
    });
  });

  describe('synthesizeToFile (via TTSService.synthesize)', () => {
    it('should generate audio with edge-tts by default', async () => {
      const options: TTSOptions = {
        text: 'Olá mundo, este é um teste de texto para fala.',
        language: 'pt-BR',
      };

      const result = await TTSService.synthesize(options);

      expect(result).toBeDefined();
      expect(result.fileUrl).toContain('https://');
      expect(result.duration).toBeGreaterThan(0);
      expect(result.voiceId).toBeDefined();
      expect(result.format).toBe('mp3');
      expect(result.provider).toBe('edge-tts');
    });

    it('should respect custom voice ID', async () => {
      const options: TTSOptions = {
        text: 'Test with custom voice.',
        voiceId: 'en-US-Neural2-A',
        language: 'en-US',
      };

      const result = await TTSService.synthesize(options);

      expect(result.voiceId).toBe('en-US-Neural2-A');
    });

    it('should estimate duration based on word count', async () => {
      // 10 words ≈ 4 seconds at 150 words/min
      const shortText: TTSOptions = {
        text: 'Um dois três quatro cinco seis sete oito nove dez.',
      };

      const result = await TTSService.synthesize(shortText);

      // Duration should be at least 1 second
      expect(result.duration).toBeGreaterThanOrEqual(1);
    });

    it('should throw on empty text', async () => {
      const options: TTSOptions = {
        text: '',
      };

      await expect(TTSService.synthesize(options)).rejects.toThrow('Text is required');
    });

    it('should throw on whitespace-only text', async () => {
      const options: TTSOptions = {
        text: '   ',
      };

      await expect(TTSService.synthesize(options)).rejects.toThrow('Text is required');
    });

    it('should select ElevenLabs when configured', async () => {
      process.env.TTS_PROVIDER = 'elevenlabs';
      process.env.ELEVENLABS_API_KEY = 'test-key';

      // Mock fetch for ElevenLabs
      const mockFetch = jest.fn().mockResolvedValue({
        ok: true,
        arrayBuffer: jest.fn().mockResolvedValue(new ArrayBuffer(100)),
      });
      global.fetch = mockFetch;

      const options: TTSOptions = {
        text: 'Test with ElevenLabs.',
        voiceId: 'some-voice-id',
      };

      const result = await TTSService.synthesize(options);

      expect(result.provider).toBe('elevenlabs');
      expect(mockFetch).toHaveBeenCalledWith(
        expect.stringContaining('api.elevenlabs.io'),
        expect.any(Object)
      );
    });

    it('should fallback to edge-tts when primary provider fails', async () => {
      process.env.TTS_PROVIDER = 'elevenlabs';
      process.env.ELEVENLABS_API_KEY = 'test-key';

      // Mock fetch to fail for ElevenLabs
      global.fetch = jest.fn().mockResolvedValue({
        ok: false,
        status: 500,
        text: jest.fn().mockResolvedValue('Internal Server Error'),
      });

      const options: TTSOptions = {
        text: 'Test fallback behavior.',
      };

      const result = await TTSService.synthesize(options);

      // Should fallback to edge-tts
      expect(result.provider).toBe('edge-tts');
    });

    it('should support custom format option', async () => {
      const options: TTSOptions = {
        text: 'Test with WAV format.',
        format: 'wav',
      };

      const result = await TTSService.synthesize(options);

      expect(result.format).toBe('wav');
    });

    it('should include metadata in idempotency key generation', async () => {
      const { generateTTSIdempotencyKey } = require('@/lib/middleware/idempotency-middleware');

      const options: TTSOptions = {
        text: 'Test with metadata.',
        metadata: { projectId: 'proj-123', slideId: 'slide-1' },
      };

      await TTSService.synthesize(options);

      expect(generateTTSIdempotencyKey).toHaveBeenCalledWith(
        'proj-123',
        'slide-1',
        'Test with metadata.',
        expect.any(String),
        expect.any(Number)
      );
    });
  });
});
